import React, { useState, useRef, useEffect } from 'react';
import { Translations } from '../../../types/i18n';

interface ChatInputProps {
  onSend: (message: string) => void;
  onExit: () => void;
  isLoading: boolean;
  t: Translations;
}

const ChatInput: React.FC<ChatInputProps> = ({ onSend, onExit, isLoading, t }) => {
  const [message, setMessage] = useState('');
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const trimmed = message.trim();
    if (!trimmed || isLoading) return;
    onSend(trimmed);
    setMessage('');
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Escape') {
      onExit();
    }
  };

  return (
    <div className="chat-input-container">
      <form onSubmit={handleSubmit} className="chat-input-form">
        <input
          ref={inputRef}
          type="text"
          value={message}
          onChange={(e) => setMessage(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder={isLoading ? t.avatar.chat.thinking : t.avatar.chat.placeholder}
          disabled={isLoading}
          maxLength={500}
          className="chat-input"
          autoComplete="off"
        />
        <button
          type="submit"
          disabled={isLoading || !message.trim()}
          className="chat-send-btn"
        >
          {isLoading ? '...' : t.avatar.chat.send}
        </button>
      </form>
      <button className="chat-exit-btn" onClick={onExit}>
        {t.avatar.chat.exit}
      </button>
    </div>
  );
};

export default ChatInput;
